/**
 * Register EventBus listeners that automatically record metrics
 * when domain events fire.
 *
 * Call this once during application bootstrap.
 *
 * Mappings:
 * - order:created  → records 'orders_count' (value: 1) AND 'revenue' (value: order.total)
 * - user:created   → records 'new_users' (value: 1)
 */
registerEventListeners(): void {
  this.logger.info('Registering analytics event listeners');

  this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
    const timestamp = event.timestamp.toISOString();

    this.recordMetric({
      metricType: 'orders_count',
      value: 1,
      timestamp,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });

    this.recordMetric({
      metricType: 'revenue',
      value: event.order.total,
      timestamp,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  });

  this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
    this.recordMetric({
      metricType: 'new_users',
      value: 1,
      timestamp: event.timestamp.toISOString(),
      metadata: { userId: event.user.id },
    });
  });
}

