/**
 * Get a summary for a single metric type over the queried range.
 *
 * Algorithm:
 * 1. Fetch current period records and compute aggregated value.
 * 2. Compute previous period (equal-length range ending at startDate).
 * 3. Calculate change percentage.
 * 4. Build time-series by bucketing current period records.
 */
getMetricSummary(metricType: MetricType, query: AnalyticsQuery): MetricSummary {
  this.logger.info(`Computing summary for metric: ${metricType}`);

  const currentRecords = this.analyticsRepository.findByTypeAndDateRange(
    metricType,
    query.startDate,
    query.endDate,
  );

  const currentValue = this.aggregateValue(metricType, currentRecords, query);

  // Previous period: equal-length range ending at startDate
  const start = new Date(query.startDate);
  const end = new Date(query.endDate);
  const periodMs = end.getTime() - start.getTime();
  const prevStart = new Date(start.getTime() - periodMs);
  const prevEnd = new Date(start.getTime());

  const previousRecords = this.analyticsRepository.findByTypeAndDateRange(
    metricType,
    prevStart.toISOString(),
    prevEnd.toISOString(),
  );

  const previousValue = this.aggregateValue(metricType, previousRecords, query);

  const changePercent =
    previousValue === 0
      ? null
      : ((currentValue - previousValue) / previousValue) * 100;

  const granularity = query.granularity ?? 'day';
  const timeSeries = this.buildTimeSeries(currentRecords, granularity);

  return {
    metricType,
    currentValue,
    previousValue,
    changePercent,
    timeSeries,
  };
}

