  /**
   * Get raw time-series data points for a single metric.
   *
   * Useful for detailed drill-down charts where the caller wants
   * finer control over presentation than MetricSummary provides.
   */
  getTimeSeries(
    metricType: MetricType,
    query: AnalyticsQuery,
  ): TimeSeriesPoint[] {
    this.logger.info(`Generating time series for: ${metricType}`);

    const granularity: TimeGranularity = query.granularity ?? 'day';

    const records = this.analyticsRepository.findByTypeAndDateRange(
      metricType,
      query.startDate,
      query.endDate,
    );

    return this.buildTimeSeries(records, granularity);
  }

  // -----------------------------------------------------------------------
  // Private helpers
  // -----------------------------------------------------------------------

  /**
   * Aggregate raw records into a single numeric value.
   *
   * For `average_order_value`, computes revenue / order count using
   * the revenue and orders_count records from the same period.
   * For all other metrics, sums the values.
   */
  private aggregateValue(
    metricType: MetricType,
    records: MetricRecord[],
    query: AnalyticsQuery,
  ): number {
    if (metricType === 'average_order_value') {
      const revenueRecords = this.analyticsRepository.findByTypeAndDateRange(
        'revenue',
        query.startDate,
        query.endDate,
      );
      const orderRecords = this.analyticsRepository.findByTypeAndDateRange(
        'orders_count',
        query.startDate,
        query.endDate,
      );
      const totalRevenue = revenueRecords.reduce((sum, r) => sum + r.value, 0);
      const totalOrders = orderRecords.reduce((sum, r) => sum + r.value, 0);
      return totalOrders === 0 ? 0 : totalRevenue / totalOrders;
    }

    return records.reduce((sum, r) => sum + r.value, 0);
  }

  /**
   * Bucket records by granularity and sum values per bucket.
   * Returns sorted TimeSeriesPoint[].
   */
  private buildTimeSeries(
    records: MetricRecord[],
    granularity: TimeGranularity,
  ): TimeSeriesPoint[] {
    const buckets = new Map<string, number>();

    for (const record of records) {
      const key = bucketTimestamp(record.timestamp, granularity);
      buckets.set(key, (buckets.get(key) ?? 0) + record.value);
    }

    const points: TimeSeriesPoint[] = [];
    for (const [timestamp, value] of buckets) {
      points.push({ timestamp, value });
    }

    points.sort((a, b) => a.timestamp.localeCompare(b.timestamp));
    return points;
  }
}

// ---------------------------------------------------------------------------
// Time bucketing utility
// ---------------------------------------------------------------------------

/**
 * Truncate an ISO-8601 timestamp to the start of its time bucket.
 *
 * - 'hour'  → truncate to start of hour
 * - 'day'   → truncate to start of day (UTC)
 * - 'week'  → truncate to Monday 00:00 UTC
 * - 'month' → truncate to 1st of month 00:00 UTC
 */
export function bucketTimestamp(
  isoTimestamp: string,
  granularity: TimeGranularity,
): string {
  const date = new Date(isoTimestamp);

  switch (granularity) {
    case 'hour':
      date.setUTCMinutes(0, 0, 0);
      break;
    case 'day':
      date.setUTCHours(0, 0, 0, 0);
      break;
    case 'week': {
      // Shift to Monday: getUTCDay() returns 0=Sun, 1=Mon, ..., 6=Sat
      const day = date.getUTCDay();
      const diff = day === 0 ? 6 : day - 1; // days since last Monday
      date.setUTCDate(date.getUTCDate() - diff);
      date.setUTCHours(0, 0, 0, 0);
      break;
    }
    case 'month':
      date.setUTCDate(1);
      date.setUTCHours(0, 0, 0, 0);
      break;
  }

  return date.toISOString();
}

